import java.io.BufferedReader;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;

public class Valley {
	/**	Aceasta functie reprezinta rezolvarea efectiva a problemei.
	 * 	Parametrii sunt: indexul inaltimii minime, numarul de varfuri
	 * 	si vectorul de varfuri.
	 * 	Prima data se verifica daca sirul de varfuri reprezinta
	 * 	o panta sau o rampa. Acest lucru se afla prin pozitia celui
	 * 	mai mic varf. Daca sirul este o panta, atunci penultimul varf ia valoarea
	 * 	varfului min, altfel, daca sirul este o rampa, al doilea vard ia acea
	 * 	valoare.
	 * 	Daca nu s-au gasit cazurile precizate mai devreme, atunci se lucreaza pe
	 * 	cele doua jumatati:
	 * 	- prefixul de la 0 la min_index - 1;
	 * 	- sufixul de la N-1 la min_index + 1.
	 * 	In parcurgerea prefixului, daca varful din stanga este mai mic decat cel din dreapta,
	 * 	atunci varful din dreapta se micsoreaza cu o valoare egala cu diferenta dintre cele
	 * 	doua varfuri. Aceasta diferenta se adauga la numarul total de ore necesare pentru
	 * 	excavare.
	 * 	In parcurgerea sufixului, daca varful din dreapta este mai mic decat cel din stanga,
	 * 	atunci varful din stanga se micsoreaza cu o valoare egala cu diferenta dintre cele
	 * 	doua varfuri. Aceasta diferenta se adauga la numarul total de ore necesare pentru
	 * 	excavare.
	 * 	La final, functia returneaza numarul de ore necesare pentru a forma o vale.
	 * */
	public static long solveValley(int min_index, int N, int[] v) {
		long hours = 0;
		int dif;
		if (min_index == N - 1) {
			dif = v[N - 2] - v[N - 1];
			hours += dif;
			v[N - 2] -= dif;
		} else if (min_index == 0) {
			dif = v[1] - v[0];
			hours += dif;
			v[1] -= dif;
		}
		for (int i = 0; i < min_index; i++) {
			if (v[i] < v[i + 1]) {
				dif = v[i + 1] - v[i];
				hours += dif;
				v[i + 1] -= dif;
			}
		}
		for (int i = N - 1; i > min_index; i--) {
			if (v[i] < v[i - 1]) {
				dif = v[i - 1] - v[i];
				hours += dif;
				v[i - 1] -= dif;
			}
		}

		return hours;
	}
	public static void main(String[] args) {
		int N = 0;
		int[] v = new int[0];
		int min = Integer.MAX_VALUE;
		int min_index = 0;

		// Se citesc datele din fisier
		try {
			BufferedReader br = new BufferedReader(new FileReader("valley.in"));
			String buffer = br.readLine();
			N = Integer.parseInt(buffer);
			v = new int[N];
			buffer = br.readLine();
			String[] ints = buffer.split(" ");
			for (int i = 0; i < N; i++) {
				v[i] = Integer.parseInt(ints[i]);
				if (v[i] < min) {
					min = v[i];
					min_index = i;
				}
			}
		} catch (IOException e) {
			e.printStackTrace();
		}

		// Se scriu datele in fisier
		try {
			FileWriter myWriter = new FileWriter("valley.out");
			myWriter.write("" + solveValley(min_index, N, v));
			myWriter.close();
		} catch (IOException e) {
			e.printStackTrace();
		}
	}
}

#include <iostream>
#include <fstream>
#include <vector>

int main() {
    std::ifstream in("valley.in");
    std::ofstream out("valley.out");

    int n;
    in >> n;

    std::vector<int> heights(n, 0);

    // read into array and find minimums and indices
    int min = INT32_MAX, first_min, last_min;
    for (auto i = 0; i < n; i++) {
        in >> heights[i];

        if (heights[i] < min) {
            if (heights[i] == min) {
                last_min = i;
            } else {
                first_min = i;
                last_min = i;
            }

            min = heights[i];
        }
    }

    in.close();

    int lefth = heights[0];
    int righth = heights[n - 1];

    unsigned long long count = 0;

    // check for edge case min first
    int min_first_case = 0;
    if (last_min == 0) {
        count += (heights[1] - heights[0]);
        min_first_case = 1;
    }

    // check for edge case min last
    int min_last_case = 0;
    if (first_min == n - 1) {
        count += (heights[n - 2] - heights[n - 1]);
        min_last_case = 1;
    }

    // calculate from start to first min
    for (auto i = 0; i < first_min - min_last_case; i++) {
        if (heights[i] < lefth)
            lefth = heights[i];
        else
            count += (heights[i] - lefth);
    }

    // calculate from first min to last min
    for (auto i = first_min + 1; i < last_min; i++)
        count += (heights[i] - min);

    // calculate from last min to end
    for (auto i = n - 1; i > last_min + min_first_case; i--) {
        if (heights[i] < righth)
            righth = heights[i];
        else
            count += (heights[i] - righth);
    }

    out << count;
    out.close();
    return 0;
}
